## NuGet Packages

```
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
```

## Program.cs

```csharp
using OpenTelemetry.Logs;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "MyApp";
var serviceVersion = "1.0.0";

var otelEndpoint = builder.Configuration["Otel:Endpoint"]
    ?? "http://localhost:4317";

// Shared resource for all signals
var resource = ResourceBuilder.CreateDefault()
    .AddService(serviceName: serviceName, serviceVersion: serviceVersion);

// --- Traces ---
builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName, serviceVersion: serviceVersion))
    .WithTracing(tracing =>
    {
        tracing
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddOtlpExporter(o => o.Endpoint = new Uri(otelEndpoint));
    })
    .WithMetrics(metrics =>
    {
        metrics
            .AddAspNetCoreInstrumentation()
            .AddHttpClientInstrumentation()
            .AddRuntimeInstrumentation()
            .AddOtlpExporter(o => o.Endpoint = new Uri(otelEndpoint));
    });

// --- Logs ---
builder.Logging.AddOpenTelemetry(logging =>
{
    logging.SetResourceBuilder(resource);
    logging.IncludeFormattedMessage = true;
    logging.IncludeScopes = true;
    logging.AddOtlpExporter(o => o.Endpoint = new Uri(otelEndpoint));
});

builder.Services.AddControllers();

var app = builder.Build();

app.MapControllers();
app.Run();
```

### Key points

- **`AddAspNetCoreInstrumentation()`** — auto-instruments inbound HTTP requests (traces + metrics).
- **`AddHttpClientInstrumentation()`** — auto-instruments outbound `HttpClient` calls.
- **`AddRuntimeInstrumentation()`** — emits .NET runtime metrics (GC, threadpool). Requires the `OpenTelemetry.Instrumentation.Runtime` package if you include it — install with `dotnet add package OpenTelemetry.Instrumentation.Runtime`.
- **OTLP default** is gRPC on port `4317`. Use `4318` with `OtlpExportProtocol.HttpProtobuf` if your collector expects HTTP/protobuf.
- The collector endpoint is read from config (`Otel:Endpoint`), so you can override it per-environment via `appsettings.{env}.json` or env var `Otel__Endpoint`.
